+    if (offset == (map->adr_at(c)->_offset + map->adr_at(c)->_size)) {
+      //contiguous to the last field, can be coalesced
+      map->adr_at(c)->_size = map->adr_at(c)->_size + size;
+      inserted = true;
+      break;  // break out of the for loop
